local function GetDistanceToPlayer(Pos) local A=localPlayer.Character and localPlayer.Character:FindFirstChild("HumanoidRootPart") and localPlayer.Character.HumanoidRootPart.Position or camera.CFrame.Position return (A-Pos).Magnitude end
local function AddESP(part,txt,color) ESPLibrary:AddESP({Object=part,Text=txt,Color=color}) end
local function AddEntityESP(part,txt,color) if part:IsA("Model") then while not part.PrimaryPart do for _,v in pairs(part:GetChildren()) do if v:IsA("BasePart") then part.PrimaryPart=v end end task.wait() end if part.PrimaryPart then part.PrimaryPart.Transparency=0.99 end if not part:FindFirstChildOfClass("Humanoid") then Instance.new("Humanoid",part) end end if part.Name=="FigureRig" or part.Name=="FigureRagdoll" then part:WaitForChild("Root").Size=Vector3.new(0.001,0.001,0.001) end ESPLibrary:AddESP({Object=part,Text=txt,Color=color}) end
local function GetLibraryCode() local CL=ReplicatedStorage.GameData.Floor.Value=="Fools" and 10 or 5 local Slot=table.create(CL,"_") local Paper for _,plr in pairs(Players:GetPlayers()) do local char=plr.Character if char then Paper=char:FindFirstChild("LibraryHintPaper") or char:FindFirstChild("LibraryHintPaperHard") or plr.Backpack:FindFirstChild("LibraryHintPaper") or plr.Backpack:FindFirstChild("LibraryHintPaperHard") if Paper then break end end end if not Paper then return table.concat(Slot) end local Hints=localPlayer.PlayerGui.PermUI.Hints:GetChildren() for _,i in pairs(Paper.UI:GetChildren()) do if i:IsA("ImageLabel") and i.Name~="Image" then local Pos=tonumber(i.Name) if Pos and Slot[Pos] then for _,v in pairs(Hints) do if v.Name=="Icon" and v.ImageRectOffset.X==i.ImageRectOffset.X then local L=v:FindFirstChild("TextLabel") if L then Slot[Pos]=L.Text end break end end end end end return table.concat(Slot) end

