function ShowSeekPath(v) local P=Instance.new("Part",SeekPath) P.Size=Vector3.new(1.5,1.5,1.5) P.Anchored=true P.Shape="Ball" P.Position=v.Position P.CanCollide=false P.Color=Color3.new(0,1,0) Debris:AddItem(P,60) end
function FixBridge(v) for _,i in pairs(v:GetChildren()) do if i.Name=="PlayerBarrier" and i.Rotation.X==180 then local B=i:Clone() B.CFrame=CFrame.new(i.Position.X,i.Position.Y,i.Position.Z)*CFrame.new(0,-7,0) B.Size=Vector3.new(40,0.1,40) B.Transparency=0.5 B.Color=Color3.new(0.5,0,0.5) B.Material="ForceField" B.Parent=v B.Name="BridgeBarrier" B.Anchored=true B.CanCollide=true end end end
function PathTo(Pos) local C=localPlayer.Character local R=C and C:FindFirstChild("HumanoidRootPart") local H=C and C:FindFirstChild("Humanoid") if not R or not H then return end local p=PathfindingService:CreatePath({AgentRadius=2,AgentHeight=5,AgentCanJump=true,WaypointSpacing=2,AgentMaxSlope=45,AgentJumpHeight=0}) p:ComputeAsync(R.Position,Pos+Vector3.new(0,0,1)) if p.Status~=Enum.PathStatus.Success then return end for _,wp in ipairs(p:GetWaypoints()) do if not Toggles.AutoRooms.Value or Library.Unloaded then break end if (R.Position-wp.Position).Magnitude>=2 then H:MoveTo(wp.Position) H.MoveToFinished:Wait() end end end
function Breaker(part) local label=part:WaitForChild("SurfaceGui"):WaitForChild("Frame"):WaitForChild("Code") local function run() task.wait(0.05) if not Toggles.AutoBreaker.Value then return end if Method=="Exploit" then RemotesFolder.EBF:FireServer() return end if Method=="Legit" then local target=tonumber(label.Text) if target then for _,v in part:GetChildren() do if v.Name=="BreakerSwitch" and v:GetAttribute("ID")==target then local trans=part.SurfaceGui.Frame.Code:WaitForChild("Frame").BackgroundTransparency local pc=v:FindFirstChild("PrismaticConstraint") local light=v:FindFirstChild("Light") local sound=v:FindFirstChild("Sound") if trans==0 then if v:GetAttribute("Enabled") then return end v:SetAttribute("Enabled",true) if pc then pc.TargetPosition=-0.2 end if light then light.Material=Enum.Material.Neon local sp=light:FindFirstChild("Spark",true) if sp then sp:Emit(1) end end if sound then sound:Play() end elseif trans==1 then if not v:GetAttribute("Enabled") then return end v:SetAttribute("Enabled",false) if pc then pc.TargetPosition=0.2 end if light then light.Material=Enum.Material.Glass end if sound then sound:Play() end end break end end end end end label:GetPropertyChangedSignal("Text"):Connect(run) run() end

