local function InfPrompt(Prompt) local Char=localPlayer.Character if not Char then return end local Tool=Char:FindFirstChild("Lockpick") or Char:FindFirstChild("SkeletonKey") or Char:FindFirstChild("Shears") local Name=Tool and Tool.Name if Tool then if not Prompt:GetAttribute("InfItems") then Prompt.Enabled=false Prompt:SetAttribute("InfItems",true) Prompt:SetAttribute("Tool",Name) Prompt.ClickablePrompt=false local Clone=Prompt:Clone() Clone.Name="InfPrompt" Clone.MaxActivationDistance=Prompt.MaxActivationDistance*0.5 Clone.Parent=Prompt.Parent Clone.Enabled=true Clone.ClickablePrompt=true local Con Con=Clone.Triggered:Connect(function() Con:Disconnect() Clone:Destroy() if Char:FindFirstChild(Name) then task.spawn(function() local Drop=nil local st=tick() repeat RemotesFolder.DropItem:FireServer(Tool) task.wait(0.01) local cd=15 for _,v in ipairs(workspace.Drops:GetChildren()) do if v.Name==Name then local d=GetDistanceToPlayer(v:GetPivot().Position) if d<cd then cd=d Drop=v end end end until Drop or not Char:FindFirstChild(Name) or (tick()-st)>3 if Drop and Firepp then local dp=Drop:FindFirstChildWhichIsA("ProximityPrompt",true) if dp then fireproximityprompt(dp) end end if Firepp then fireproximityprompt(Prompt) end Prompt:SetAttribute("InfItems",nil) Prompt:SetAttribute("Tool",nil) Prompt.Enabled=true Prompt.ClickablePrompt=true end) else Prompt:SetAttribute("InfItems",nil) Prompt.Enabled=true Prompt.ClickablePrompt=true end end) end end end

