-- bypass loops + engine
task.spawn(function() while task.wait(Options.SpeedBypassMethod.Value=="Method 1" and 0 or 0.209) do if Library.Unloaded then break end if Options.SpeedBypassMethod.Value=="Method 1" then if Toggles.BypassSpeed.Value then if CollisionClone then CollisionClone.Massless=true end RemotesFolder.Crouch:FireServer(true,true) end elseif Options.SpeedBypassMethod.Value=="Method 2" then local char=localPlayer.Character local hrp=char and char:FindFirstChild("HumanoidRootPart") if localPlayer:GetAttribute("Alive") and hrp and CollisionClone and CollisionClone.Parent then Params.FilterDescendantsInstances={char,CollisionClone} if not workspace:Raycast(hrp.Position,Vector3.new(0,-100,0),Params) or not Toggles.BypassSpeed.Value then CollisionClone.Massless=true else if localPlayer:GetAttribute("Alive") then CollisionClone.Massless=true end task.wait(0.209) if localPlayer:GetAttribute("Alive") and CollisionClone and CollisionClone.Parent then CollisionClone.Massless=false end end end end end end)
if HookMeta then local Old Old=hookmetamethod(game,"__namecall",function(Self,...) if Library.Unloaded then return Old(Self,...) end local Mm=getnamecallmethod() if Mm=="FireServer" or Mm=="InvokeServer" then if Toggles.AutoHeartbeat.Value and Self.Name=="ClutchHeartbeat" then return Old(Self,true) end if Mm=="FireServer" and Toggles.FigureHearing.Value and Self.Name=="Crouch" then return Old(Self,true,true) end end return Old(Self,...) end) end
local getcons=getconnections or get_signal_cons or get_relative_connections
if getcons then for _,c in pairs(getcons(localPlayer.Idled)) do if c.Disable then c:Disable() end end end

local AI,NC,AAS,IID,PE=0,0,0,0,0
table.insert(Connections,RunService.RenderStepped:Connect(function(dt)
    AI+=dt NC+=dt AAS+=dt IID+=dt PE+=dt
    if not localPlayer:GetAttribute("Alive") then if Toggles.InfRevive.Value then RemotesFolder.Revive:FireServer() end if CollisionClone then CollisionClone=nil end return end
    if camera~=workspace.CurrentCamera then camera=workspace.CurrentCamera end
    if not localPlayer.Character:GetAttribute("Climbing") and Toggles.EnableMovementSpeed.Value then if localPlayer.Character.Humanoid.WalkSpeed~=Options.MovementSpeed.Value then localPlayer.Character.Humanoid.WalkSpeed=Options.MovementSpeed.Value end end
    camera.FieldOfView=Options.FOV.Value
    if Toggles.Freecam.Value then local char=localPlayer.Character local hum=char and char:FindFirstChild("Humanoid") local root=char and char:FindFirstChild("HumanoidRootPart") if root and not root.Anchored then root.Anchored=true end if not workspace:FindFirstChild("FreecamPart") then local part=Instance.new("Part") part.Name="FreecamPart" part.Size=Vector3.new(0.01,0.01,0.01) part.Transparency=1 part.CanCollide=false part.Anchored=true part.CFrame=camera.CFrame part.Parent=workspace localPlayer:SetAttribute("fc_om",localPlayer.CameraMinZoomDistance) localPlayer:SetAttribute("fc_ox",localPlayer.CameraMaxZoomDistance) localPlayer.CameraMinZoomDistance=0 localPlayer.CameraMaxZoomDistance=0 local rx,ry=camera.CFrame:ToOrientation() localPlayer:SetAttribute("fc_p",math.deg(rx)) localPlayer:SetAttribute("fc_y",math.deg(ry)) end local fc=workspace:FindFirstChild("FreecamPart") if fc then local d=UserInputService:GetMouseDelta() local sens=UserInputService.KeyboardEnabled and 0.3 or 0.6 local pitch=math.clamp((localPlayer:GetAttribute("fc_p") or 0)-(d.Y*sens),-80,80) local yaw=(localPlayer:GetAttribute("fc_y") or 0)-(d.X*sens) localPlayer:SetAttribute("fc_p",pitch) localPlayer:SetAttribute("fc_y",yaw) fc.CFrame=CFrame.new(fc.Position)*CFrame.fromOrientation(math.rad(pitch),math.rad(yaw),0) camera.CFrame=fc.CFrame camera.Focus=camera.CFrame*CFrame.new(0,0,-10) if hum and hum.MoveDirection.Magnitude>0 then local mv=hum.MoveDirection local lm=camera.CFrame:VectorToObjectSpace(mv) local fm=(camera.CFrame.RightVector*lm.X)+(camera.CFrame.LookVector*-lm.Z) fc.Position=fc.Position+(fm*75*dt) end end end
    if Toggles.DeleteFigureFE.Value and Figures then for _,v in pairs(Figures) do local Root=v:FindFirstChild("Root") if not IsNetworkOwner then Toggles.DeleteFigureFE:SetValue(false) elseif Root and isnetworkowner(Root) then if Root:FindFirstChild("BodyForce") then Root.BodyForce.Force=Vector3.new(0,-50000,0) else Root:PivotTo(CFrame.new(0,-50000,0)) end for _,part in pairs(v:GetDescendants()) do if part:IsA("BasePart") and part.CanCollide then part.CanCollide=false part.Anchored=false end end end end end
    if Toggles.AutoAnchorSolver.Value and LatestRoom.Value==50 and AAS>0.5 then AAS=0 local Hint=localPlayer.PlayerGui.MainUI:FindFirstChild("AnchorHintFrame") if Anchors and Hint and Hint.Visible then local ID=Hint.AnchorCode.Text for _,v in pairs(Anchors) do if v:FindFirstChild("Sign") and v.Sign.TextLabel.Text==ID then local Code=Hint.Code.Text if (localPlayer.Character.HumanoidRootPart.Position-v:GetPivot().Position).Magnitude<20 then local AR=v:FindFirstChildOfClass("RemoteFunction") if AR then AR:InvokeServer(tostring(Code)) end end end end end end
    if Toggles.InfItems.Value and IID>0.15 then IID=0 for _,p in pairs(Stored) do InfPrompt(p) end end
    if Toggles.NotifyLibraryCode.Value and NC>5 then NC=0 local Code=GetLibraryCode() if Code and LatestRoom.Value==50 then Notify("Doors","Code "..Code) end end
    if Toggles.AutoLibraryCode.Value and LatestRoom.Value==50 then local Code=GetLibraryCode() if Code then if Toggles.BruteForceLibCode.Value and string.find(Code,"_") then local B="" for i=1,#Code do local c=string.sub(Code,i,i) B=B..(c=="_" and tostring(math.random(0,9)) or c) end Code=B end PL:FireServer(Code) end end
    if Toggles.Flight.Value then if not localPlayer.Character.HumanoidRootPart:FindFirstChild("FlightVelocity") then local V=Instance.new("BodyVelocity",localPlayer.Character.HumanoidRootPart) V.MaxForce=Vector3.new(math.huge,math.huge,math.huge) V.Velocity=Vector3.zero V.Name="FlightVelocity" V.P=math.huge end local md=localPlayer.Character.Humanoid.MoveDirection local fl=camera.CFrame.LookVector*Vector3.new(1,0,1) if fl.Magnitude<0.001 then fl=camera.CFrame.UpVector*Vector3.new(1,0,1)*math.sign(-camera.CFrame.LookVector.Y) end local fc2=CFrame.lookAt(Vector3.zero,fl) local li=fc2:VectorToObjectSpace(md) localPlayer.Character.HumanoidRootPart.FlightVelocity.Velocity=camera.CFrame:VectorToWorldSpace(li)*Options.FlightSpeed.Value end
    if Toggles.Godmode.Value and RemotesFolder.Name=="RemotesFolder" then if not Toggles.FigureHearing.Value then Toggles.FigureHearing:SetValue(true) end if localPlayer.Character.LowerTorso.Root.C1~=CFrame.new(0,-2.3,0) then localPlayer.Character.LowerTorso.Root.C1=CFrame.new(0,-2.3,0) end if localPlayer.Character.Humanoid.HipHeight~=0.22 then localPlayer.Character.Humanoid.HipHeight=0.22 end if localPlayer.Character.Collision.Size~=Vector3.new(1,1,4) then localPlayer.Character.Collision.Size=Vector3.new(1,1,4) end if localPlayer.Character.Collision.CollisionCrouch.Size~=Vector3.new(1,1,4) then localPlayer.Character.Collision.CollisionCrouch.Size=Vector3.new(1,1,4) end end
    if not localPlayer.Character:FindFirstChild("CollisionClone") then if localPlayer.Character:FindFirstChild("CollisionPart") then CollisionClone=localPlayer.Character.CollisionPart:Clone() CollisionClone.Parent=localPlayer.Character CollisionClone.Name="CollisionClone" CollisionClone.RootPriority=127 CollisionClone.Anchored=false CollisionClone.CanCollide=false if CollisionClone:FindFirstChild("CollisionCrouch") then CollisionClone.CollisionCrouch:Destroy() end end end
    if Toggles.NoAcc.Value and not Toggles.Flight.Value then if localPlayer.Character.HumanoidRootPart.CustomPhysicalProperties~=PhysicalProperties.new(100,0.1,0.1,0.1,0.1) then localPlayer.Character.HumanoidRootPart.CustomPhysicalProperties=PhysicalProperties.new(100,0.1,0.1,0.1,0.1) end end
    if Toggles.EnableJump.Value and not localPlayer.Character:GetAttribute("CanJump") then localPlayer.Character:SetAttribute("CanJump",true) end
    if Toggles.AutoInteract.Value and AI>Options.AutoInteractDelay.Value then AI=0 if localPlayer.Character and localPlayer.Character:FindFirstChild("HumanoidRootPart") then for _,prompt in Interactions do if not prompt.Parent then continue end if (prompt.Parent.Name=="GoldPile" and CurrentFloor=="Fools") or prompt.Parent.Name=="KeyObtainFake" or prompt.Parent.Name=="Mandrake" then continue end if prompt:GetAttribute("InfItems") and prompt.Name~="InfPrompt" then continue end if prompt.Parent:IsA("BasePart") or prompt.Parent:IsA("Model") then local TP=prompt.Parent:IsA("BasePart") and prompt.Parent or (prompt.Parent.PrimaryPart or prompt.Parent:FindFirstChildWhichIsA("BasePart")) if TP and (localPlayer.Character.HumanoidRootPart.Position-TP.Position).Magnitude<=Options.AutoInteractreach.Value then if not prompt.Enabled then prompt.Enabled=true end if Firepp then fireproximityprompt(prompt) else prompt:InputHoldBegin() prompt:InputHoldEnd(prompt.HoldDuration or 0) end end end end end end
    if Toggles.NoFog.Value then if Lighting.FogEnd<100000 then Lighting.FogEnd=100000 end for _,a in pairs(Lighting:GetChildren()) do if a:IsA("Atmosphere") and a.Density>0 then a.Density=0 end end end
    if Toggles.NoCamShake.Value and RequiredMainGame then RequiredMainGame.csgo=CFrame.new(0,0,0) end
    if Toggles.Player.Value and PE>1 then PE=0 for _,v in pairs(Players:GetPlayers()) do if v~=localPlayer and v.Character then local h=v.Character:FindFirstChildOfClass("Humanoid") if h then if h.Health>0 then AddESP(v.Character,v.Name.." ["..math.floor((h.Health/h.MaxHealth)*100).."%]",PlayerColor) else ESPLibrary:RemoveESP(v.Character) end end end end end
    if Toggles.EyesDamage.Value then if (workspace:FindFirstChild("Eyes") or workspace:FindFirstChild("Lookman")) and not localPlayer.Character:GetAttribute("Hiding") then if RemotesFolder.Name~="RemotesFolder" then MotorReplication:FireServer(0,-650,0,false) else MotorReplication:FireServer(-650) end end end
    if Toggles.LookmanDamage.Value then if workspace:FindFirstChild("BackdoorLookman") and not localPlayer.Character:GetAttribute("Hiding") then MotorReplication:FireServer(-650) end end
    if Toggles.FullBright.Value then if Lighting.Ambient~=Color3.new(1,1,1) then Lighting.Ambient=Color3.new(1,1,1) end local cr=workspace.CurrentRooms:FindFirstChild(tostring(localPlayer:GetAttribute("CurrentRoom"))) if cr then if not cr:GetAttribute("OldAmbient") then cr:SetAttribute("OldAmbient",cr:GetAttribute("Ambient")) end if cr:GetAttribute("Ambient")~=Color3.new(1,1,1) then cr:SetAttribute("Ambient",Color3.new(1,1,1)) end end end
    if Toggles.AntiCheatMani.Value and localPlayer.Character and localPlayer.Character:FindFirstChild("HumanoidRootPart") then if Options.AntiCheatManiMethod.Value=="Velocity" then local BV=localPlayer.Character.HumanoidRootPart:FindFirstChild("VelocityMani") or Instance.new("BodyVelocity",localPlayer.Character.HumanoidRootPart) local lv=localPlayer.Character.HumanoidRootPart.CFrame.LookVector*2 BV.Velocity=Vector3.new(lv.X,lv.Y,lv.Z) BV.MaxForce=Vector3.new(math.huge,math.huge,math.huge) BV.Name="VelocityMani" else localPlayer.Character:PivotTo(localPlayer.Character:GetPivot()*CFrame.new(0,0,10000)) end end
    if Options.AutoInteractKeybind:GetState() and not Toggles.AutoInteract.Value then Toggles.AutoInteract:SetValue(true) end
    if not Options.AutoInteractKeybind:GetState() and Toggles.AutoInteract.Value then Toggles.AutoInteract:SetValue(false) end
    if Options.AntiCheatMan:GetState() and not Toggles.AntiCheatMani.Value then Toggles.AntiCheatMani:SetValue(true) end
    if not Options.AntiCheatMan:GetState() and Toggles.AntiCheatMani.Value then Toggles.AntiCheatMani:SetValue(false) end
end))

table.insert(Connections,workspace.ChildAdded:Connect(function(v) if Toggles.AntiBanana and Toggles.AntiBanana.Value and v.Name=="BananaPeel" then v.CanTouch=false end if Toggles.NotifySpawn.Value then local m=workspaceEntities[v.Name] if m and Options.Notify.Value[m=="A-60" and "A-60" or m] then Notify("Doors",m.." has Spawned") end end if Toggles.Entity.Value then local lab=workspaceEntities[v.Name] if lab then AddEntityESP(v,lab,EntityColor) end end end))
table.insert(Connections,workspace.DescendantAdded:Connect(function(v) local t=0 repeat task.wait(0.03) t+=0.03 until v.Parent or t>0.5 if not v.Parent then return end if v.Parent:FindFirstChildOfClass("Humanoid") then return end if HidingPlaces[v.Name] then table.insert(Closets,v) end if Toggles.Ladder.Value and v.Name=="Ladder" then AddESP(v,"Ladder",LadderColor) end if Toggles.Fuse.Value and v.Name=="FuseObtain" then AddESP(v,"Fuse",FuseColor) end if Toggles.Gold.Value and v.Name=="GoldPile" then AddESP(v,"Gold "..v:GetAttribute("GoldValue"),GoldColor) end if Toggles.Books.Value and v.Name=="LiveHintBook" then AddESP(v,"Library Book",BookColor) end if Toggles.Breakers.Value and v.Name=="LiveBreakerPolePickup" then AddESP(v,"Breaker",BreakerColor) end if Toggles.Objective.Value then local b=Items[v.Name] if b then AddESP(v,b,ItemsColor) end end if Toggles.AutoBreaker.Value and v.Name=="ElevatorBreaker" then Breaker(v) end if Toggles.InstaInteract.Value and v:IsA("ProximityPrompt") then v:SetAttribute("Duration",v.HoldDuration) v.HoldDuration=0 end if Toggles.PromptReach.Value and v:IsA("ProximityPrompt") then v:SetAttribute("Range",v.MaxActivationDistance) v.MaxActivationDistance=v.MaxActivationDistance*2 end if Toggles.PromptClip.Value and v:IsA("ProximityPrompt") then v:SetAttribute("Clip",v.RequiresLineOfSight) v.RequiresLineOfSight=false end if Toggles.InfItems.Value and v:IsA("ProximityPrompt") then if Names[v.Parent.Name] or v.Name=="FusesPrompt" or v.Parent.Parent.Name=="Locker_Small_Locked" then table.insert(Stored,v) end end if Toggles.AutoInteract.Value and v:IsA("ProximityPrompt") then if not (PromptIgnore[v.Name] or v.Parent.Name=="Padlock" or v.Parent:GetAttribute("JeffShop")) then table.insert(Interactions,v) end end if Toggles.Entity.Value and roomEntities[v.Name] then AddEntityESP(v,roomEntities[v.Name],EntityColor) end if Toggles.DeleteFigureFE.Value and (v.Name=="FigureRig" or v.Name=="FigureRagdoll") then table.insert(Figures,v) end if Toggles.AutoMinecart.Value then if v.Name=="DuckBoard" then table.insert(DuckBoards,v) end if string.find(v.Name,"MinecartNode") then table.insert(Nodes,v) end end if Toggles.AutoAnchorSolver.Value and v.Name=="MinesAnchor" then table.insert(Anchors,v) end end))
table.insert(Connections,workspace.DescendantRemoving:Connect(function(v) for i,g in pairs(Interactions) do if g==v then table.remove(Interactions,i) break end end for i,g in pairs(Closets) do if v==g then table.remove(Closets,i) end end for i,k in pairs(Stored) do
if v==k then table.remove(Stored,i) end end end))

table.insert(Connections,localPlayer:GetAttributeChangedSignal("CurrentRoom"):Connect(function() local cr=localPlayer:GetAttribute("CurrentRoom") if Toggles.Door.Value then local OD=workspace.CurrentRooms[cr-1] and workspace.CurrentRooms[cr-1].Door.Door if OD then ESPLibrary:RemoveESP(OD) end local Doo=workspace.CurrentRooms[cr+1] and workspace.CurrentRooms[cr+1].Door.Door if Doo then AddESP(Doo,"Door "..Doo.Parent:GetAttribute("RoomID"),DoorColor) end end if Toggles.GateLever.Value then local L=workspace.CurrentRooms[cr] and workspace.CurrentRooms[cr]:FindFirstChild("LeverForGate",true) if L then AddESP(L,"Gate Lever",LeverColor) end end if Toggles.Objective.Value then local Key=workspace.CurrentRooms[cr] and workspace.CurrentRooms[cr]:FindFirstChild("KeyObtain",true) if Key then AddESP(Key,"Key",ItemsColor) end end end))

Notify("Doors","Loaded for "..(isBricks and "Backdoor" or CurrentFloor))
